mapper.select:
SELECT COUNT(*) AS total
FROM exercises e


        AND e.creator = #{userId}


        AND e.class_id = #{classId}

SELECT c.class_name AS className, u.user_name AS userName, co.course_name AS courseName,
FROM exercises e LEFT JOIN class c ON c.id = e.class_id LEFT JOIN course co ON co.id = c.course_id LEFT JOIN `user` u ON u.id = e.creator
AND e.creator = #{userId}
AND e.class_id = #{classId}
ORDER BY e.id DESC LIMIT #{page},#{pageSize}

SELECT COUNT(*) AS total FROM exercises e LEFT JOIN user_do_exercise ude ON e.id = ude.exercise_id
e.class_id = #{classId}
AND (ude.user_id != #{userId} OR ude.user_id IS NULL)

SELECT c.class_name AS className, u.user_name AS userName, co.course_name AS courseName,
FROM exercises e LEFT JOIN class c ON c.id = e.class_id LEFT JOIN course co ON co.id = c.course_id LEFT JOIN `user` u ON u.id = e.creator LEFT JOIN user_do_exercise ude ON e.id = ude.exercise_id
e.class_id = #{classId}
AND (ude.user_id != #{userId} OR ude.user_id IS NULL)
ORDER BY e.id DESC LIMIT #{page},#{pageSize}
